import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Box,
  Paper,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TablePagination,
  Chip,
  IconButton,
  Tooltip,
  TextField,
  InputAdornment,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogContentText,
  DialogActions,
  LinearProgress,
  Tabs,
  Tab,
} from '@mui/material';
import {
  Add,
  Search,
  Edit,
  Delete,
  Inventory,
  Refresh,
  Warning,
  CheckCircle,
  Category,
  LocalOffer,
  Straighten,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { itemService } from '../../services/itemService';

const ItemList = () => {
  const navigate = useNavigate();
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [totalElements, setTotalElements] = useState(0);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  const [tabValue, setTabValue] = useState(0);

  useEffect(() => {
    fetchItems();
  }, [page, rowsPerPage]);

  const fetchItems = async () => {
    try {
      setLoading(true);
      const data = await itemService.getAll(page, rowsPerPage, search);
      setItems(data.content || []);
      setTotalElements(data.totalElements || 0);
    } catch (error) {
      toast.error('Failed to fetch items');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (value) => {
    setSearch(value);
    setPage(0);
    fetchItems();
  };

  const handleDelete = async () => {
    try {
      await itemService.delete(selectedItem.id);
      toast.success('Item deleted successfully');
      setDeleteDialogOpen(false);
      fetchItems();
    } catch (error) {
      toast.error('Failed to delete item');
    }
  };

  const getStockStatus = (item) => {
    if (item.currentStock <= 0) {
      return { label: 'Out of Stock', color: 'error', icon: <Warning /> };
    }
    if (item.currentStock <= item.reorderLevel) {
      return { label: 'Low Stock', color: 'warning', icon: <Warning /> };
    }
    return { label: 'In Stock', color: 'success', icon: <CheckCircle /> };
  };

  return (
    <Box>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Box>
          <Typography variant="h4" fontWeight="bold">
            Items
          </Typography>
          <Typography variant="body2" color="textSecondary">
            Manage your product inventory
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<Add />}
          onClick={() => navigate('/items/new')}
          sx={{ borderRadius: 2 }}
        >
          Add Item
        </Button>
      </Box>

      <Tabs value={tabValue} onChange={(e, v) => setTabValue(v)} sx={{ mb: 2 }}>
        <Tab label="All Items" icon={<Inventory />} iconPosition="start" />
        <Tab label="Low Stock" icon={<Warning />} iconPosition="start" />
        <Tab label="Brands" icon={<Category />} iconPosition="start" onClick={() => navigate('/items/brands')} />
        <Tab label="Groups" icon={<Category />} iconPosition="start" onClick={() => navigate('/items/groups')} />
        <Tab label="Sections" icon={<Category />} iconPosition="start" onClick={() => navigate('/items/sections')} />
        <Tab label="Units" icon={<Straighten />} iconPosition="start" onClick={() => navigate('/items/units')} />
        <Tab label="Taxes" icon={<LocalOffer />} iconPosition="start" onClick={() => navigate('/items/taxes')} />
      </Tabs>

      <Paper sx={{ p: 2, borderRadius: 2 }}>
        <Box display="flex" gap={2} mb={2} flexWrap="wrap">
          <TextField
            placeholder="Search items by name or code..."
            value={search}
            onChange={(e) => handleSearch(e.target.value)}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Search />
                </InputAdornment>
              ),
            }}
            sx={{ flexGrow: 1, minWidth: 200 }}
            size="small"
          />
          <Button variant="outlined" startIcon={<Refresh />} onClick={fetchItems}>
            Refresh
          </Button>
        </Box>

        {loading ? (
          <Box sx={{ width: '100%', py: 4 }}>
            <LinearProgress />
          </Box>
        ) : (
          <>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                    <TableCell>Code</TableCell>
                    <TableCell>Name</TableCell>
                    <TableCell>Brand</TableCell>
                    <TableCell>Group</TableCell>
                    <TableCell>Unit</TableCell>
                    <TableCell align="right">Price</TableCell>
                    <TableCell align="right">Stock</TableCell>
                    <TableCell>Status</TableCell>
                    <TableCell align="center">Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {items.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={9} align="center" sx={{ py: 4 }}>
                        No items found
                      </TableCell>
                    </TableRow>
                  ) : (
                    items.map((item) => {
                      const stockStatus = getStockStatus(item);
                      return (
                        <TableRow key={item.id} hover>
                          <TableCell>
                            <Typography variant="body2" fontWeight={500}>
                              {item.code}
                            </Typography>
                          </TableCell>
                          <TableCell>
                            <Box display="flex" alignItems="center" gap={1}>
                              <Inventory sx={{ color: '#1976d2', fontSize: 20 }} />
                              <Typography fontWeight={500}>{item.name}</Typography>
                            </Box>
                          </TableCell>
                          <TableCell>{item.brandName || '-'}</TableCell>
                          <TableCell>{item.groupName || '-'}</TableCell>
                          <TableCell>{item.unitName || '-'}</TableCell>
                          <TableCell align="right">
                            ₹{item.sellingPrice?.toFixed(2)}
                          </TableCell>
                          <TableCell align="right">
                            <Typography
                              fontWeight={500}
                              color={item.currentStock <= item.reorderLevel ? 'error' : 'inherit'}
                            >
                              {item.currentStock}
                            </Typography>
                          </TableCell>
                          <TableCell>
                            <Chip
                              icon={stockStatus.icon}
                              label={stockStatus.label}
                              color={stockStatus.color}
                              size="small"
                              sx={{ fontWeight: 500 }}
                            />
                          </TableCell>
                          <TableCell align="center">
                            <Tooltip title="Edit">
                              <IconButton
                                size="small"
                                color="primary"
                                onClick={() => navigate(`/items/edit/${item.id}`)}
                              >
                                <Edit />
                              </IconButton>
                            </Tooltip>
                            <Tooltip title="Delete">
                              <IconButton
                                size="small"
                                color="error"
                                onClick={() => {
                                  setSelectedItem(item);
                                  setDeleteDialogOpen(true);
                                }}
                              >
                                <Delete />
                              </IconButton>
                            </Tooltip>
                          </TableCell>
                        </TableRow>
                      );
                    })
                  )}
                </TableBody>
              </Table>
            </TableContainer>

            <TablePagination
              rowsPerPageOptions={[5, 10, 25, 50]}
              component="div"
              count={totalElements}
              rowsPerPage={rowsPerPage}
              page={page}
              onPageChange={(e, newPage) => setPage(newPage)}
              onRowsPerPageChange={(e) => {
                setRowsPerPage(parseInt(e.target.value, 10));
                setPage(0);
              }}
            />
          </>
        )}
      </Paper>

      <Dialog open={deleteDialogOpen} onClose={() => setDeleteDialogOpen(false)}>
        <DialogTitle>Delete Item</DialogTitle>
        <DialogContent>
          <DialogContentText>
            Are you sure you want to delete item "{selectedItem?.name}"?
            This action cannot be undone.
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteDialogOpen(false)}>Cancel</Button>
          <Button onClick={handleDelete} color="error" variant="contained">
            Delete
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default ItemList;
